package org.eclipse.rdf4j.query.algebra.evaluation.trace;

import java.util.Objects;

/**
 * Thread-local trace recorder scope used by the exact execution trace demo.
 */
public final class QueryTraceContext {

	private static final ThreadLocal<State> CURRENT = new ThreadLocal<>();

	private QueryTraceContext() {
	}

	public static Activation activate(QueryTraceRecorder recorder) {
		QueryTraceRecorder nextRecorder = Objects.requireNonNull(recorder, "Recorder was null");
		State previous = CURRENT.get();
		State next = new State(nextRecorder, previous);
		CURRENT.set(next);
		return () -> {
			State current = CURRENT.get();
			if (current != next) {
				return;
			}
			if (previous == null) {
				CURRENT.remove();
			} else {
				CURRENT.set(previous);
			}
		};
	}

	public static QueryTraceRecorder getRecorder() {
		State state = CURRENT.get();
		return state == null ? null : state.recorder;
	}

	public interface Activation extends AutoCloseable {
		@Override
		void close();
	}

	private static final class State {
		private final QueryTraceRecorder recorder;
		private final State previous;

		private State(QueryTraceRecorder recorder, State previous) {
			this.recorder = recorder;
			this.previous = previous;
		}
	}
}
